document.addEventListener("DOMContentLoaded",function(){"use strict";var t=document.getElementById("text-input"),e=document.getElementById("clear-btn"),n=document.getElementById("result-chars"),l=document.getElementById("result-chars-no-space"),o=document.getElementById("result-lines"),r=document.getElementById("result-paragraphs"),a=document.getElementById("result-bytes"),c=document.getElementById("result-manuscript");function i(){var e=t.value,i=e.replace(/\n/g,"").length;n.textContent=i.toLocaleString();var u=e.replace(/[\s\n]/g,"").length;if(l.textContent=u.toLocaleString(),""===e)o.textContent="0";else{var d=e.split("\n").length;o.textContent=d.toLocaleString()}if(""===e.trim())r.textContent="0";else{var s=e.split(/\n\s*\n/).filter(function(t){return""!==t.trim()}).length;r.textContent=s.toLocaleString()}var g=new Blob([e]).size;a.textContent=g.toLocaleString()+" バイト";var m=Math.floor(i/400),v=i%400;c.textContent=m+"枚と"+v+"文字"}t.addEventListener("input",i),e.addEventListener("click",function(){t.value="",i()})});